func TestRouterMetrics_ConcurrentUpdates(t *testing.T) {
	registry := metric.NewMetricsRegistry()
	metrics := getMetrics(registry)

	// Simulate concurrent router operations
	done := make(chan struct{})

	go func() {
		for i := 0; i < 100; i++ {
			metrics.recordMessageReceived("cli")
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	go func() {
		for i := 0; i < 100; i++ {
			metrics.recordTaskSubmitted()
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	go func() {
		for i := 0; i < 50; i++ {
			metrics.recordLoopStarted()
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	// Wait for all goroutines
	<-done
	<-done
	<-done

	// Verify all updates were recorded (no race conditions)
	cliMessages := getCounterValue(t, metrics.messagesReceived, "cli")
	assert.GreaterOrEqual(t, cliMessages, float64(100), "Should have at least 100 CLI messages")

	tasks := getSimpleCounterValue(t, metrics.tasksSubmitted)
	assert.GreaterOrEqual(t, tasks, float64(100), "Should have at least 100 tasks")

	active := getGaugeValue(t, metrics.activeLoops)
	assert.GreaterOrEqual(t, active, float64(50), "Should have at least 50 active loops")
}

